function NFA_SEARCH(pattern P[1..m], text T[1..n]):
  // Build NFA with m+1 states
  NFA = buildPatternNFA(P)
  active_states = {start_state}
  matches = []

  for i from 1 to n:
    // Compute ε-closure
    active_states = epsilonClosure(active_states)
    // Process current character
    new_states = {}
    for each state q in active_states:
      for each transition δ(q, T[i]):
        add target to new_states
    active_states = new_states

    // Check if accepting state (complete match) is reached
    if accepting_state in active_states:
      add (i - m + 1) to matches  // Match ends at position i

  return matches

function BUILD_DFA(pattern P[1..m], alphabet Σ):
  // Initialize DFA with (m+1) states 0 to m
  create array DFA[0..m][Σ]

  // For each state q and symbol a, compute next state
  for q from 0 to m:
    for each a in Σ:
      // Find longest prefix of P that's suffix of (P[1..q] + a)
      temp = P[1..q] + a  // Concatenate
      while not isPrefixOf(P, temp):
        temp = temp[2..]  // Remove first char
      DFA[q][a] = length_of_longest_prefix_matched(temp)

  return DFA
